// Define text documents to process
const BASE = 'https://raw.githubusercontent.com/YOUR_USERNAME/YOUR_REPO/main/';

const docs = [
  { 
    url: BASE + 'meeting_notes_q3.txt',
    label: 'Q3 Engineering Meeting Notes',
    type: 'meeting_notes'
  },
  { 
    url: BASE + 'project_updates.txt',
    label: 'Project Status Updates',
    type: 'status_update'
  }
];

return docs.map(d => ({ json: d }));

const response = $input.first().json.response;

// Parse the LLM response
let extracted;
try {
  // Remove markdown code fences if present
  const cleaned = response.replace(/```json\n?|```\n?/g, '').trim();
  extracted = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse LLM response as JSON: ' + e.message + '\nResponse: ' + response);
}

// Validate required fields
if (!extracted.people) extracted.people = [];
if (!extracted.projects) extracted.projects = [];
if (!extracted.decisions) extracted.decisions = [];
if (!extracted.documents) extracted.documents = [];

// Add teams array (extract unique teams from people)
const teams = [...new Set(extracted.people.map(p => p.team).filter(Boolean))];
extracted.teams = teams;

return [{ json: extracted }];

const data = $input.first().json;

const schemaQueries = [
  "CREATE CONSTRAINT person_id IF NOT EXISTS FOR (n:Person) REQUIRE n.id IS UNIQUE",
  "CREATE CONSTRAINT project_id IF NOT EXISTS FOR (n:Project) REQUIRE n.id IS UNIQUE",
  "CREATE CONSTRAINT decision_id IF NOT EXISTS FOR (n:Decision) REQUIRE n.id IS UNIQUE",
  "CREATE CONSTRAINT document_id IF NOT EXISTS FOR (n:Document) REQUIRE n.id IS UNIQUE",
  "CREATE CONSTRAINT skill_name IF NOT EXISTS FOR (n:Skill) REQUIRE n.name IS UNIQUE",
  "CREATE CONSTRAINT tool_name IF NOT EXISTS FOR (n:Tool) REQUIRE n.name IS UNIQUE",
  "CREATE CONSTRAINT team_name IF NOT EXISTS FOR (n:Team) REQUIRE n.name IS UNIQUE",
  "CREATE VECTOR INDEX doc_embeddings IF NOT EXISTS FOR (n:Document) ON n.embedding OPTIONS {indexConfig: {`vector.dimensions`: 384, `vector.similarity_function`: 'cosine'}}",
  "CREATE VECTOR INDEX decision_embeddings IF NOT EXISTS FOR (n:Decision) ON n.embedding OPTIONS {indexConfig: {`vector.dimensions`: 384, `vector.similarity_function`: 'cosine'}}"
];

const dataQueries = [
  {
    query: "UNWIND $teams AS t MERGE (:Team {name: t})",
    parameters: { teams: data.teams || [] }
  },
  {
    query: `UNWIND $people AS p
            MERGE (person:Person {id: p.id})
            SET person.name = p.name, person.role = coalesce(p.role, ''), person.bio = coalesce(p.bio, '')
            WITH person, p
            OPTIONAL MATCH (t:Team {name: p.team})
            FOREACH (_ IN CASE WHEN t IS NULL THEN [] ELSE [1] END | MERGE (person)-[:MEMBER_OF]->(t))`,
    parameters: { people: data.people || [] }
  },
  {
    query: `UNWIND $projects AS pr
            MERGE (project:Project {id: pr.id})
            SET project.name = pr.name, project.description = coalesce(pr.description, ''),
                project.status = coalesce(pr.status, 'unknown')
            FOREACH (tool IN coalesce(pr.tools, []) | MERGE (t:Tool {name: tool}) MERGE (project)-[:USED_TOOL]->(t))
            FOREACH (cid IN coalesce(pr.contributors, []) | MERGE (cp:Person {id: cid}) MERGE (cp)-[:WORKED_ON]->(project))`,
    parameters: { projects: data.projects || [] }
  },
  {
    query: `UNWIND $decisions AS d
            MERGE (dec:Decision {id: d.id})
            SET dec.title = d.title, dec.rationale = coalesce(d.rationale, ''), 
                dec.date = coalesce(d.date, ''), dec.status = coalesce(d.status, 'unknown')
            WITH dec, d
            OPTIONAL MATCH (p:Person {id: d.approved_by})
            FOREACH (_ IN CASE WHEN p IS NULL THEN [] ELSE [1] END | MERGE (p)-[:APPROVED]->(dec))
            WITH dec, d
            OPTIONAL MATCH (pr:Project {id: d.project_id})
            FOREACH (_ IN CASE WHEN pr IS NULL THEN [] ELSE [1] END | MERGE (dec)-[:RELATES_TO]->(pr))`,
    parameters: { decisions: data.decisions || [] }
  },
  {
    query: `UNWIND $documents AS d
            MERGE (doc:Document {id: d.id})
            SET doc.title = d.title, doc.content = coalesce(d.content, ''), 
                doc.type = coalesce(d.type, 'document'), doc.created = coalesce(d.created, '')
            WITH doc, d
            OPTIONAL MATCH (p:Person {id: d.author_id})
            FOREACH (_ IN CASE WHEN p IS NULL THEN [] ELSE [1] END | MERGE (p)-[:AUTHORED]->(doc))
            WITH doc, d
            OPTIONAL MATCH (dec:Decision {id: d.documents_decision})
            FOREACH (_ IN CASE WHEN dec IS NULL THEN [] ELSE [1] END | MERGE (doc)-[:DOCUMENTS]->(dec))
            WITH doc, d
            OPTIONAL MATCH (pr:Project {id: d.documents_project})
            FOREACH (_ IN CASE WHEN pr IS NULL THEN [] ELSE [1] END | MERGE (doc)-[:DOCUMENTS]->(pr))`,
    parameters: { documents: data.documents || [] }
  }
];

return [{ json: { schemaQueries, dataQueries } }];
